import { create } from 'zustand'

const useProgressBarStore = create((set) => ({
    progressBars: [],
    queue: [],
    activeId: null,

    addProgressBar: () => set((state) => {
        const id = state.progressBars.length
        const newBar = { id, completed: false }

        if (state.activeId === null) {
            return { progressBars: [...state.progressBars, newBar], activeId: id }
        }

        return { progressBars: [...state.progressBars, newBar], queue: [...state.queue, id] }
    }),

    completeProgressBar: (id) => set((state) => {
        const [nextId, ...rest] = state.queue
        return {
            progressBars: state.progressBars.map(pb => pb.id === id ? { ...pb, completed: true } : pb),
            queue: rest,
            activeId: nextId ?? null
        }
    })
}))

export default useProgressBarStore
